import axios from 'axios';

// Create axios instance with base URL pointing to backend on port 8085
const api = axios.create({
  baseURL: 'http://localhost:8085/api', // Direct connection to backend
  withCredentials: true, // Include cookies in requests
});

// Add token to requests if available
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Response interceptor for error handling
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      // Token expired or invalid
      localStorage.removeItem('token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// Auth API
export const authAPI = {
  login: (credentials) => api.post('/auth/login', credentials),
  register: (userData) => api.post('/auth/register', userData),
  logout: () => api.post('/auth/logout'),
  forgotPassword: (email) => api.post('/auth/forgot-password', { email }),
};

// Cart API
export const cartAPI = {
  getCart: (userId) => api.get(`/cart/${userId}`),
  addItem: (userId, item) => api.post(`/cart/${userId}/items`, item),
  removeItem: (userId, itemId) => api.delete(`/cart/${userId}/items/${itemId}`),
  updateQuantity: (userId, itemId, data) => api.put(`/cart/${userId}/items/${itemId}`, data),
  clearCart: (userId) => api.delete(`/cart/${userId}`),
};

// Books API
export const booksAPI = {
  getBooks: (params) => api.get('/books', { params }),
  getBook: (id) => api.get(`/books/${id}`),
};

// Export default api instance for other uses
export default api;
